import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Select, Pagination, StatusBadge, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { ProductionOrderDto, ProductionOrderStatus } from '../../../services/sx/models';
import { formatDateLocal, formatNumber, formatPercent } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const PAGE_SIZE = 20;

const STATUS_OPTIONS = [
  { value: '', label: 'Tất cả trạng thái' },
  { value: 'Draft', label: 'Nháp' },
  { value: 'Released', label: 'Đã phát lệnh' },
  { value: 'InProgress', label: 'Đang SX' },
  { value: 'Completed', label: 'Hoàn thành' },
  { value: 'Closed', label: 'Đóng' },
];

const LsxListPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const navigate = useNavigate();

  const [status, setStatus] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [items, setItems] = useState<ProductionOrderDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [actionId, setActionId] = useState<string | null>(null);

  const load = () => {
    setLoading(true);
    sxService
      .getProductionOrders({ status: status || undefined, page: currentPage, pageSize: PAGE_SIZE })
      .then(res => {
        setItems(res.items);
        setTotalCount(res.totalCount);
      })
      .catch(err => {
        dispatch(addToast({ message: err?.message ?? 'Lỗi tải danh sách LSX', type: 'error' }));
      })
      .finally(() => setLoading(false));
  };
  const handleSearch = () => setReloadKey(k => k + 1);
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      if (!cancelled) load();
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [status, currentPage]);

  const handleRelease = async (id: string) => {
    setActionId(id);
    try {
      await sxService.releaseProductionOrder(id);
      dispatch(addToast({ message: 'Phát lệnh sản xuất thành công', type: 'success' }));
      load();
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Phát lệnh thất bại', type: 'error' }));
    } finally {
      setActionId(null);
    }
  };

  const handleComplete = async (id: string) => {
    setActionId(id);
    try {
      await sxService.completeProductionOrder(id);
      dispatch(addToast({ message: 'Hoàn thành lệnh SX thành công', type: 'success' }));
      load();
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Hoàn thành thất bại', type: 'error' }));
    } finally {
      setActionId(null);
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-industry" /> Lệnh sản xuất</h1>
        </div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={() => navigate('/sx/lsx/them')}>
            <i className="fas fa-plus" /> Tạo LSX
          </Button>
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`erp-lsx-filters`}>
        <Select
          value={status}
          onChange={e => { setStatus(e.target.value); setCurrentPage(1); }}
          options={STATUS_OPTIONS}
          size="small"
        />
        <ListSearchRefreshButtons testIdPrefix="erp-lsx" onSearch={handleSearch} onRefresh={refresh} showSearch={false} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : items.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có lệnh sản xuất</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Số LSX</th>
                  <th>Ngày</th>
                  <th>Sản phẩm</th>
                  <th className={styles.colRight}>SL đặt</th>
                  <th className={styles.colRight}>Hoàn thành</th>
                  <th>Hạn</th>
                  <th>Trạng thái</th>
                  <th className={styles.colActions}></th>
                </tr>
              </thead>
              <tbody>
                {items.map(r => {
                  const pct = formatPercent(r.completedQty, r.orderQty);
                  return (
                    <tr key={r.id}>
                      <td>
                        <button type="button" className={styles.codeLink} onClick={() => navigate(`/sx/lsx/${r.id}`)}>
                          <code>{r.code}</code>
                        </button>
                      </td>
                      <td>{formatDateLocal(r.orderDate)}</td>
                      <td>{r.productName ?? r.productCode}</td>
                      <td className={styles.colRight}>{formatNumber(r.orderQty)}</td>
                      <td className={styles.colRight}>
                        {formatNumber(r.completedQty)}{' '}
                        <span className={styles.tagDefault}>({pct}%)</span>
                      </td>
                      <td>{formatDateLocal(r.plannedEndDate)}</td>
                      <td><StatusBadge status={r.status as ProductionOrderStatus} /></td>
                      <td className={styles.colActions}>
                        <button type="button" className={styles.actionBtn} onClick={() => navigate(`/sx/lsx/${r.id}`)} title="Sửa">
                          <i className="fas fa-edit" />
                        </button>
                        {r.status === 'Draft' && (
                          <button
                            type="button"
                            className={styles.actionBtn}
                            disabled={actionId === r.id}
                            onClick={() => handleRelease(r.id)}
                            title="Phát lệnh"
                          >
                            <i className="fas fa-play" />
                          </button>
                        )}
                        {(r.status === 'Released' || r.status === 'InProgress') && (
                          <button
                            type="button"
                            className={styles.actionBtn}
                            disabled={actionId === r.id}
                            onClick={() => handleComplete(r.id)}
                            title="Hoàn thành"
                          >
                            <i className="fas fa-check" />
                          </button>
                        )}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
        {totalCount > 0 && (
          <div className={styles.paginationRow}>
            <span className={styles.totalCount}>Tổng: {totalCount} lệnh</span>
            <Pagination
              currentPage={currentPage}
              totalPages={Math.ceil(totalCount / PAGE_SIZE)}
              totalCount={totalCount}
              pageSize={PAGE_SIZE}
              onPageChange={setCurrentPage}
            />
          </div>
        )}
      </div>
    </div>
  );
};

export default LsxListPage;
